<template>
    <div>
        <div class="row">
          
            <div class="col-md-12 pt-0 mb-2 mt-2">
                <div class="col-sm-12 col-md-12 col-lg-6 col-xl-6 p-0">
                    <div class="mr-2 d-inline-block">
                        <span class="legend-pending colorboxsquare"></span> {{ $t("ServiceValidation") }}
                    </div>
                    <div class="mr-2 d-inline-block">
                        <span class="legend-upcoming colorboxsquare"></span> {{ $t("LeafNodeValidation") }}
                    </div>
                </div>
                <div class="heading-border mb-3">
                        <h5 class="h5"><span>{{ $t("RootNode") }}</span></h5>
                </div>
                <RecursiveNodeConfiguration :rules="rules" :name="'RecursiveNodeConfiguration'"
                    :configurationId="configurationId" :reqType="reqType" :serviceId="serviceId" :mode="mode" @rule-merged="handleRuleMerged" 
                    :isBillingType="isBillingType" :clientId="clientId" :setupId="setupId"></RecursiveNodeConfiguration>
            </div>
            <div class="col-md-12 pb-2" v-if="rules.length == 0">
                <div class="border-bottom text-center text-danger p-2">
                    {{ $t("NorecordfoundText") }}
                </div>
            </div>
        </div>
       
        <div class="text-right mb-2" v-if="mode !== 'View'">
            <button type="button" class="btn btn-info mr-2" @click="addMoreRule">
                <em class="fa fa-plus"></em> {{ $t("AddMoreRule") }}
            </button>
            
            <button type="button" class="btn btn-success mr-2" @click="saveServiceRules">
                <em class="fa fa-save"></em> {{ $t("SaveRule") }}
            </button>
            <button type="button" class="btn btn-danger" @click="RuleCancel">
                <em class="fa fa-times"></em> {{ $t("Cancel") }}
            </button>
        </div>
    </div>
</template>
<script>
import DataServices from "./../../../services/DataService";
import RecursiveNodeConfiguration from "./RecursiveNodeConfiguration.vue";
export default {
    components: { "RecursiveNodeConfiguration": RecursiveNodeConfiguration },
    props: {
        configurationId: {
            type: String,
            default: null
        },
        reqType: {
            type: String,
            default: null
        },
        serviceId:{
            type: String,
            default: null
        },
        mode: {
            type: String,
            default: 'Edit'
        },
        isBillingType :{
            type: Boolean,
            required: false
        },
        clientId:{
            type: Number,
            default: null
        },
        setupId:{
            type: Number,
            default: null
        }
    },
    data: function () {
        return {
            rules: [],
            jsonToSaveRules: [],
            processedData: []
        }
    },
    created: function () {
        var vm = this;
        this.serviceId = this.reqType === 'fromServiceMapping' ? this.serviceId : parseInt(this.$route.params.serviceId);  
        this.getNodeConfiguration();
       
    },
    methods: {
        RuleCancel:function() {
            var vm = this;
            if(vm.reqType == 'fromServiceMapping'){
                this.$parent.$parent.$parent.isModalBillingConfiguration=false;
                this.$parent.$parent.$parent.FetchData();
            }
            else
            {
                vm.$router.push({name: vm.isBillingType ? 'BillingRule' : 'BillingRuleListing'});
            }
        },
        handleRuleMerged(ruleList) {
            this.rules = ruleList;
        },
        makeJsonForSave: function (rule) {
            let ths = this;
            var isUpdate = false;
            if (rule.ruleCondition.hasOwnProperty('isUpdateRule')) {
                isUpdate = rule.ruleCondition.isUpdateRule;
            }
            var objRule = {
                ruleId: rule.ruleId,
                ruleName: rule.ruleName,
                conditionId: rule.ruleCondition.conditionId,
                rateCodeId: rule.ruleCondition.rateCode,
                isLeafChecked: rule.ruleCondition.isLeafChecked,
                usageBased: rule.ruleCondition.addAdder,
                usageBasedSlabs: rule.ruleCondition.adderRows,
                usageBasedType: rule.ruleCondition.adderType,
                selectedflag: rule.ruleCondition.selectedFlag.value,
                version: rule.version,
                parent: rule.parent,
                isDelete: rule.isDelete,
                isUpdateRule: isUpdate,
                dependentOnServices: rule.ruleCondition.dependentOnServices,
                dependentPrice: rule.ruleCondition.dependentPrice,
                dependentType: rule.ruleCondition.dependentType,
                functionType: rule.ruleCondition.functionType

            }
            this.jsonToSaveRules.push(objRule);
            rule.rules.forEach(function (itm, index) {
                ths.makeJsonForSave(itm);
            });
        },
        saveServiceRules: function () {
            let ths = this;
            var obj = {
                //planServiceId: item.plan_service_id,
                configurationId: this.configurationId,
                rules: []
            };
            this.jsonToSaveRules = [];
            this.rules.forEach(function (rule, index) {
                ths.makeJsonForSave(rule);
            });
            obj.rules = ths.jsonToSaveRules;
            debugger;
            console.log("saveServiceRules = ", obj)
            // DataServices.SaveServiceRules(JSON.stringify(obj),this.isBillingType).then(function (response) {
            //     debugger;
            //     if (response && response.data != null && response.data.status == "Success") {
            //         ths.ShowAlert(ths.$t('SuccessfullySaved', [ths.$t('BillingRuleConfiguration')]), "success", true, ths.$t("Alert"));
            //         ths.getNodeConfiguration();
            //     }
            // })
        },
        addMoreRule: function () {
            var vm = this;
            var lastRule = vm.rules[vm.rules.length - 1];
            // var version = Number(lastRule.version); // convert to number
            // var newVersion = version + 1;
            var version = lastRule.version === 'GLOBAL' ? 0 : Number(lastRule.version);
            var newVersion = version + 1;
            vm.rules.push({
                ruleId: 0,
                ruleDisplayOrder: (vm.rules.length + 1),
                // ruleName: "Rule " + (vm.rules.length + 1),
                // version: (vm.rules.length + 1),
                ruleName: "Rule " + newVersion,
                version: newVersion,
                ruleCondition: {},
                rules: [],
                parent: null,
                isDelete: false,
                isShowChild: true,
                hidebuttons: true,
                isUpdateRule: true
            })
        },
        // getNodeConfiguration: function () {
        //     let ths = this;
        //     ths.rules = [];
        //     ths.processedData = [];
        //     var prms = `configId=${this.configurationId}`;
        //     DataServices.GetNodeConfigurationData(prms).then(function (res) {
        //         if (res && res.data) {
        //             let dt = res.data;
        //             let data = [];
        //             var filterParentNode = dt.filter((item) => { return item.PARENT_MAPPING_ID == null });
        //               filterParentNode.forEach(function (item, index) {
        //                 if (!ths.processedData.includes(item.CLIENT_SERVICE_MAPPING_ID)) {
        //                     var obj = {
        //                         ruleId: item.CLIENT_SERVICE_MAPPING_ID,
        //                         ruleDisplayOrder: item.DISPLAY_ORDER,
        //                         ruleName: "Rule " + item.DISPLAY_NODE_NAME,
        //                         version: item.DISPLAY_NODE_NAME,
        //                         ruleCondition: {
        //                             conditionId: item.SERVICE_ID,
        //                             serviceName: item.SERVICE_NAME,
        //                             rateCode: "",
        //                             isLeafChecked: item.IS_LEAF_NODE,
        //                             condition: item.CONDITION,
        //                             selectedFlag: {
        //                                 value: "grey",
        //                                 name: "grey"
        //                             },
        //                             nodeName: item.DISPLAY_NODE_NAME,
        //                             dependentOnServices: null,
        //                             dependentPrice: 0,
        //                             dependentType: '',
        //                             functionType: ''

        //                         },
        //                         rules: [],
        //                         parent: null,
        //                         isDelete: false,
        //                         isShowChild: true
        //                     }
        //                     let filteredData = dt.filter((itm) => { return itm.PARENT_MAPPING_ID == item.CLIENT_SERVICE_MAPPING_ID });
        //                     let child = [];
        //                     if (filteredData.length > 0) {
        //                         child = ths.getChildJson(filteredData, dt, item.CLIENT_SERVICE_MAPPING_ID, item.DISPLAY_NODE_NAME);
        //                     }
        //                     obj.rules = child;
        //                     ths.processedData.push(item.CLIENT_SERVICE_MAPPING_ID);
        //                     data.push(obj);
        //                 }
        //             });
        //             ths.rules = data;
        //             if (ths.rules.length == 0) {
        //                 ths.addMoreRule();
        //             }
        //         }
        //     });
        // },
        getNodeConfiguration: function () {
            let ths = this;
            ths.rules = [];
            ths.processedData = [];
            if(ths.isBillingType == true){
                var prms = `configId=${this.configurationId}&serviceId=${this.serviceId}&isIncludeGlobalService=true&isView=${this.$route.params.mode}`;
                DataServices.GetNodeConfigurationData(prms).then(function (res) {
                    if (res && res.data) {
                        debugger;
                        let dt = res.data;
                        let data = [];
                        let globalCounter = 1;
                        let rootItems = dt.filter(item => item.PARENT_MAPPING_ID === 0 || item.PARENT_MAPPING_ID === null);

                        // Helper function to create the object
                        function createRuleObject(item) {
                            return {
                                ruleId: item.CLIENT_SERVICE_MAPPING_ID,
                                ruleDisplayOrder: item.DISPLAY_ORDER,
                                ruleName: item.DISPLAY_NODE_NAME.toUpperCase() === "GLOBAL" ?  `Global ${globalCounter++}`  : "Rule " + item.DISPLAY_NODE_NAME,
                                version: item.DISPLAY_NODE_NAME,
                                ruleCondition: {
                                    conditionId: item.SERVICE_ID,
                                    serviceName: item.SERVICE_NAME,
                                    rateCode: "",
                                    isLeafChecked: item.IS_LEAF_NODE,
                                    condition: item.CONDITION,
                                    selectedFlag: {
                                        value: "grey",
                                        name: "grey"
                                    },
                                    nodeName: item.DISPLAY_NODE_NAME,
                                    dependentOnServices: null,
                                    dependentPrice: 0,
                                    dependentType: '',
                                    functionType: ''
                                },
                                rules: [],
                                parent: null,
                                isDelete: false,
                                isShowChild: true
                            };
                        }

                        // Process root items
                        rootItems.forEach(function (item) {
                            let obj = createRuleObject(item);
                            ths.processedData.push(item.CLIENT_SERVICE_MAPPING_ID);
                            data.push(obj);
                        });

                        // Process other items
                        dt.forEach(function (item) {
                            if (!ths.processedData.includes(item.CLIENT_SERVICE_MAPPING_ID)) {
                                let obj = createRuleObject(item);

                                let filteredData = dt.filter(itm => itm.PARENT_MAPPING_ID == item.CLIENT_SERVICE_MAPPING_ID);
                                if (filteredData.length > 0) {
                                    obj.rules = ths.getChildJson(filteredData, dt, item.CLIENT_SERVICE_MAPPING_ID, item.DISPLAY_NODE_NAME);
                                }

                                ths.processedData.push(item.CLIENT_SERVICE_MAPPING_ID);
                                data.push(obj);
                            }
                        });

                        ths.rules = data;
                        if (ths.rules.length == 0) {
                            ths.addMoreRule();
                        }
                    }
                });
            }
            else
            {
                var prms = `configId=${this.configurationId}`;
                DataServices.GetNodeConfigurationData(prms).then(function (res) {
                    if (res && res.data) {
                        let dt = res.data;
                        let data = [];
                        var filterParentNode = dt.filter((item) => { return item.PARENT_MAPPING_ID == null });
                        filterParentNode.forEach(function (item, index) {
                            if (!ths.processedData.includes(item.CLIENT_SERVICE_MAPPING_ID)) {
                                var obj = {
                                    ruleId: item.CLIENT_SERVICE_MAPPING_ID,
                                    ruleDisplayOrder: item.DISPLAY_ORDER,
                                    ruleName: "Rule " + item.DISPLAY_NODE_NAME,
                                    version: item.DISPLAY_NODE_NAME,
                                    ruleCondition: {
                                        conditionId: item.SERVICE_ID,
                                        serviceName: item.SERVICE_NAME,
                                        rateCode: "",
                                        isLeafChecked: item.IS_LEAF_NODE,
                                        condition: item.CONDITION,
                                        selectedFlag: {
                                            value: "grey",
                                            name: "grey"
                                        },
                                        nodeName: item.DISPLAY_NODE_NAME,
                                        dependentOnServices: null,
                                        dependentPrice: 0,
                                        dependentType: '',
                                        functionType: ''

                                    },
                                    rules: [],
                                    parent: null,
                                    isDelete: false,
                                    isShowChild: true
                                }
                                let filteredData = dt.filter((itm) => { return itm.PARENT_MAPPING_ID == item.CLIENT_SERVICE_MAPPING_ID });
                                let child = [];
                                if (filteredData.length > 0) {
                                    child = ths.getChildJson(filteredData, dt, item.CLIENT_SERVICE_MAPPING_ID, item.DISPLAY_NODE_NAME);
                                }
                                obj.rules = child;
                                ths.processedData.push(item.CLIENT_SERVICE_MAPPING_ID);
                                data.push(obj);
                            }
                        });
                        ths.rules = data;
                        if (ths.rules.length == 0) {
                            ths.addMoreRule();
                        }
                    }
                });
            }
            
        },

        getChildJson: function (filterData, dt, clientMappingId, parentNode) {
            let ths = this;
            let returnValue = []
            filterData.forEach(function (item, index) {
                var obj = {
                    ruleId: item.CLIENT_SERVICE_MAPPING_ID,
                    ruleDisplayOrder: item.DISPLAY_ORDER,
                    ruleName: "Rule " + item.DISPLAY_NODE_NAME,
                    version: item.DISPLAY_NODE_NAME,
                    ruleCondition: {
                        conditionId: item.SERVICE_ID,
                        serviceName: item.SERVICE_NAME,
                        rateCode: "",
                        isLeafChecked: item.IS_LEAF_NODE,
                        condition: item.CONDITION,
                        selectedFlag: {
                            value: "grey",
                            name: "grey"
                        },
                        nodeName: item.DISPLAY_NODE_NAME
                    },
                    rules: [],
                    parent: parentNode,
                    isDelete: false,
                    isShowChild: true
                }
                let filteredData = dt.filter((itm) => { return itm.PARENT_MAPPING_ID == item.CLIENT_SERVICE_MAPPING_ID });
                let child = [];
                if (filteredData.length > 0) {
                    child = ths.getChildJson(filteredData, dt, item.CLIENT_SERVICE_MAPPING_ID, item.DISPLAY_NODE_NAME);
                }
                obj.rules = child;
                ths.processedData.push(item.CLIENT_SERVICE_MAPPING_ID);
                returnValue.push(obj);
            });
            return returnValue;
        }
    },
}

</script>